class Solution:
    def largestDivisibleSubset(self, nums: List[int]) -> List[int]:
        nums.sort()
        n = len(nums)
        dp, prev = [1]*n, [-1]*n
        best, idx = 1, 0
        for i in range(n):
            for j in range(i):
                if nums[i] % nums[j] == 0 and dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1; prev[i] = j
            if dp[i] > best: best, idx = dp[i], i
        ans = []
        while idx != -1: ans.append(nums[idx]); idx = prev[idx]
        return ans

